section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/market-research-tam-sam-som.json",
  "title": "Market Research TAM SAM SOM",
  "type": "object",
  "required": [
    "artefact_id",
    "tam",
    "sam",
    "som",
    "top_down_vs_bottom_up",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "tam": {
      "type": "object",
      "description": "{value_usd, method:top-down|bottom-up, citation}"
    },
    "sam": {
      "type": "object",
      "description": "{value_usd, method, citation, filter_logic}"
    },
    "som": {
      "type": "object",
      "description": "{value_usd, method, citation, 3yr_assumption}"
    },
    "top_down_vs_bottom_up": {
      "type": "object",
      "description": "both numbers + reconciliation note"
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
